package controllers

import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Files, Paths}
import javax.inject._

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir = new File("uploads").getCanonicalFile
  
  if (!uploadsDir.exists()) {
    uploadsDir.mkdirs()
  }

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    try {
      val requestedFile = new File(uploadsDir, filename).getCanonicalFile
      
      if (!requestedFile.getCanonicalPath.startsWith(uploadsDir.getCanonicalPath + File.separator) && 
          !requestedFile.getCanonicalPath.equals(uploadsDir.getCanonicalPath)) {
        Forbidden("Access denied: Invalid file path")
      } else if (!requestedFile.exists()) {
        NotFound("File not found")
      } else if (!requestedFile.isFile) {
        BadRequest("Not a file")
      } else {
        val source = Source.fromFile(requestedFile)
        try {
          val content = source.mkString
          Ok(content).as("text/plain")
        } finally {
          source.close()
        }
      }
    } catch {
      case _: java.io.IOException => BadRequest("Invalid file path")
      case e: Exception => InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }
}